using System;`nusing GestaoManutencao.Core.Enums;`n`nnamespace GestaoManutencao.Core.Domain.Equipamentos`n{`n    public abstract class Equipamento`n    {`n        public Guid Id { get; private set; }`n        public string Descricao { get; private set; }`n        public string Marca { get; private set; }`n        public Cliente Proprietario { get; private set; }`n        public abstract EspecialidadeTecnica EspecialidadeRequerida { get; }`n`n        protected Equipamento(string descricao, string marca, Cliente proprietario)`n        {`n            if (string.IsNullOrWhiteSpace(descricao))`n                throw new ArgumentException("Descricao do equipamento eh obrigatoria.");`n            if (string.IsNullOrWhiteSpace(marca))`n                throw new ArgumentException("Marca do equipamento eh obrigatoria.");`n`n            Id = Guid.NewGuid();`n            Descricao = descricao;`n            Marca = marca;`n            Proprietario = proprietario ?? throw new ArgumentNullException(nameof(proprietario));`n        }`n    }`n}
